    public List<Integer> findSubstring(String s, String[] words){
        List<Integer> results = new ArrayList<>();
        int slidingWindowSize = words[0].length();
        Map<String,Integer> workMap = new HashMap<>();
        int counts =0;
        for(var word: words){
            workMap.compute(word, (k,v)-> v==null?1: v+1);
            counts++;
        }
        if(counts> s.length()){
            return results;
        }else if(workMap.size() ==1){
            StringBuilder buildString = new StringBuilder();
           for(int i =0; i< words.length;i++){
               buildString.append(words[0]);
           }
           String toFind = buildString.toString();
           int size  = toFind.length();
          for(int j =0; j<= s.length()-size;j++){
              String current = s.substring(j, j+size);
              if(current.equals(toFind)){
                  results.add(j);
              }
          }
           return results;

        }
        int firstPointer = 0;
        LinkedHashMap<String, Integer> holder = new LinkedHashMap<>();
        int counter = 0;
        for(int i=0; i<=s.length()-slidingWindowSize;i++){
           String current = s.substring(i,i + slidingWindowSize);
           if(workMap.get(current)!= null && (holder.get(current) == null || holder.get(current)< workMap.get(current))){
               holder.compute(current, (k,v)-> v==null? 1: v+1);
               counter++;
           }else{
               counter =0;
               i = firstPointer;
               firstPointer = firstPointer+1;
               holder = new LinkedHashMap<>();
               continue;
           }
           if(counter == words.length){
               var newImplementation = false;
               var iterator = holder.entrySet().iterator();
               if (iterator.hasNext()) {
                   var first = iterator.next(); // Get first element
                   var key  = first.getKey();
                   Set<Character> characters = new HashSet<>();
                   for(int p=0; p< key.length();p++){
                       characters.add(key.charAt(p));
                   }
                   if(characters.size()==1){
                       newImplementation= true;
                   }
                   if(holder.get(first.getKey()) ==1)
                       iterator.remove();
                   else
                       holder.put(first.getKey(), holder.get(first.getKey())-1);
               }
               results.add(firstPointer);
               i = i + slidingWindowSize-1;
               if(newImplementation){
                   counter =0;
                   i = firstPointer;
                   firstPointer = firstPointer+1;
                   holder = new LinkedHashMap<>();
                   continue;
               }else{
                   firstPointer = firstPointer+ slidingWindowSize;
               }
               counter--;
               continue;
           }
           i = i + slidingWindowSize-1;
        }
        return  results;
    }
